/**
 * CODEX/BESTIARY — Tracks all discoverable lore entries.
 * Categories: enemy, boss, character, item, card, collectible
 */

export interface CodexEntry {
  id: string;
  category: 'enemy' | 'boss' | 'character' | 'item' | 'card' | 'collectible' | 'timeline';
  name: string;
  /** Unlocked when first encountered/purchased/used */
  lore1: string;
  /** Unlocked after killing X times (enemies/bosses) or completing missions */
  lore2?: string;
  /** Kill threshold for lore2 unlock (enemies only) */
  lore2Threshold?: number;
  /** Minimum total months to unlock (null = always available via other means) */
  timelock?: number;
  /** Is this unlocked? (runtime state) */
  unlocked: boolean;
  lore2Unlocked: boolean;
}

